class Solution:
    def maxScore(self, points, m):
        # independent re-derivation: exact breadth-first search over reachable
        # per-index visit counts, correct but only intended for small inputs
        import math
        n = len(points)
        def min_moves_for_need(need):
            start_visits = tuple(min(1 if i == 0 else 0, need[i]) for i in range(n))
            if all(start_visits[i] >= need[i] for i in range(n)):
                return 1
            seen = {(0, start_visits)}
            frontier = [(0, start_visits)]
            moves = 1
            while frontier:
                nxt = []
                for pos, visits in frontier:
                    for np in (pos - 1, pos + 1):
                        if 0 <= np < n:
                            nv = list(visits)
                            nv[np] = min(nv[np] + 1, need[np])
                            nv = tuple(nv)
                            if all(nv[i] >= need[i] for i in range(n)):
                                return moves + 1
                            state = (np, nv)
                            if state not in seen:
                                seen.add(state)
                                nxt.append(state)
                frontier = nxt
                moves += 1
                if moves > 400:
                    return None
            return None
        def feasible(x):
            if x <= 0:
                return True
            need = [math.ceil(x / p) for p in points]
            bm = min_moves_for_need(need)
            return bm is not None and bm <= m
        lo, hi = 0, 1
        while feasible(hi):
            hi *= 2
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

