class Solution:
    def maxScore(self, points, m):
        n = len(points)
        def feasible(x):
            if x <= 0:
                return True
            moves = n
            carry = 0
            have_last = 0
            need_last = 0
            for i in range(n):
                have = 1 + carry
                need = (x + points[i] - 1) // points[i]
                if i == n - 1:
                    have_last = have
                    need_last = need
                if have < need:
                    deficit = need - have
                    moves += 2 * deficit
                    carry = deficit
                    if moves > m + 1:
                        return False
                else:
                    carry = 0
            if have_last > need_last:
                moves -= 1
            return moves <= m
        max_points = max(points)
        lo, hi = 0, m * max_points + 1
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

