var maxScore = function(points, m) {
    const n = points.length;
    let maxP = 0;
    for (const p of points) if (p > maxP) maxP = p;
    function feasible(x) {
        if (x <= 0) return true;
        let moves = n;
        let carry = 0;
        let haveLast = 0, needLast = 0;
        for (let i = 0; i < n; i++) {
            const have = 1 + carry;
            const need = Math.ceil(x / points[i]);
            if (i === n - 1) { haveLast = have; needLast = need; }
            if (have < need) {
                const deficit = need - have;
                moves += 2 * deficit;
                carry = deficit;
                if (moves > m + 1) return false;
            } else {
                carry = 0;
            }
        }
        if (haveLast > needLast) moves -= 1;
        return moves <= m;
    }
    let lo = 0, hi = m * maxP + 1;
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (feasible(mid)) lo = mid; else hi = mid - 1;
    }
    return lo;
};
